using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ── FormatPhoneNumber ──────────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber()
    {
        var result = _formatter.FormatPhoneNumber("1234567890");

        Assert.AreEqual("(123) 456-7890", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCode()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.StartsWith("(555)", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLineNumber()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.EndsWith("4567", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsDash()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.Contains("-", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_MatchesPattern()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.MatchesRegex(@"^\(\d{3}\) \d{3}-\d{4}$", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_Null_Throws()
    {
        Assert.ThrowsExactly<ArgumentNullException>(() => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    [DataRow("123", DisplayName = "Too short")]
    [DataRow("12345678901", DisplayName = "Too long")]
    [DataRow("", DisplayName = "Empty")]
    public void FormatPhoneNumber_WrongLength_Throws(string digits)
    {
        var ex = Assert.ThrowsExactly<ArgumentException>(() => _formatter.FormatPhoneNumber(digits));

        Assert.AreEqual("digits", ex.ParamName);
    }

    // ── BuildGreeting ──────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_DefaultTitle_StartsWithDearMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.StartsWith("Dear Mr.", result);
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.EndsWith(",", result);
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_ContainsName()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.Contains("Smith", result);
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_UsesProvidedTitle()
    {
        var result = _formatter.BuildGreeting("Jones", "Dr.");

        Assert.AreEqual("Dear Dr. Jones,", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_NullOrWhitespaceName_Throws(string? name)
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.BuildGreeting(name!));
    }

    // ── GenerateSlug ───────────────────────────────────────────────

    [TestMethod]
    [DataRow("Hello World", "hello-world")]
    [DataRow("  My  Blog  Post  ", "my-blog-post")]
    [DataRow("C# is GREAT!", "c-is-great")]
    [DataRow("already-lowercase", "already-lowercase")]
    public void GenerateSlug_VariousTitles_ReturnsExpectedSlug(string title, string expected)
    {
        var result = _formatter.GenerateSlug(title);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void GenerateSlug_Result_MatchesSlugPattern()
    {
        var result = _formatter.GenerateSlug("Some @#$ Complex!! Title");

        Assert.MatchesRegex(@"^[a-z0-9]+(-[a-z0-9]+)*$", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_NullOrWhitespace_Throws(string? title)
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.GenerateSlug(title!));
    }

    // ── FormatCurrency ─────────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(9.99m);

        Assert.StartsWith("$", result);
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(9.99m, "€");

        Assert.StartsWith("€", result);
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWith00()
    {
        var result = _formatter.FormatCurrency(42m);

        Assert.EndsWith(".00", result);
    }

    [TestMethod]
    [DataRow(19.99, "$19.99")]
    [DataRow(0.5, "$0.50")]
    [DataRow(1000, "$1000.00")]
    public void FormatCurrency_VariousAmounts_ReturnsExpected(double amount, string expected)
    {
        var result = _formatter.FormatCurrency((decimal)amount);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinus()
    {
        var result = _formatter.FormatCurrency(-5.00m);

        Assert.Contains("-", result);
    }
}

